			long expectedRows = expectedRows(workload, inputRows, topK);
			if (rowCount != expectedRows) {
				throw new IllegalStateException(workload + ": expected " + expectedRows + " rows but got " + rowCount);
			}
			return new QueryDigest(rowCount, digest);
