	static EnumMap<Workload, QueryDigest> expectedDigests(int inputRows, int topK) {
		EnumMap<Workload, QueryDigest> expected = new EnumMap<>(Workload.class);
		for (Workload workload : Workload.values()) {
			long rows = expectedRows(workload, inputRows, topK);
			long digest = DIGEST_OFFSET;
			for (long row = 0L; row < rows; row++) {
				digest = (digest ^ expectedKey(workload, inputRows, row)) * DIGEST_PRIME;
			}
			expected.put(workload, new QueryDigest(rows, digest));
		}
		return expected;
	}

	private static long expectedRows(Workload workload, int inputRows, int topK) {
		return workload == Workload.TOP_K ? topK : inputRows;
	}

	private static long expectedKey(Workload workload, int inputRows, long position) {
		return switch (workload) {
		case FULL_SORT, RADIX_ELIGIBLE -> position;
		case TOP_K, EXPRESSION_KEYS, ORDER_ELIMINATED -> inputRows - 1L - position;
		};
	}

	private static String fixedWidth(long value) {
		char[] digits = new char[FIXED_WIDTH];
		long remaining = value;
		for (int index = digits.length - 1; index >= 0; index--) {
			digits[index] = (char) ('0' + remaining % 10L);
			remaining /= 10L;
		}
		return new String(digits);
	}

	private static long parseFixedLabel(String label) {
		if (label.length() != LABEL_PREFIX.length() + FIXED_WIDTH || !label.startsWith(LABEL_PREFIX)) {
			throw new IllegalStateException("expected fixed-width label but got " + label);
		}
		long value = 0L;
		for (int index = LABEL_PREFIX.length(); index < label.length(); index++) {
			char digit = label.charAt(index);
			if (digit < '0' || digit > '9') {
				throw new IllegalStateException("expected decimal label but got " + label);
			}
			value = value * 10L + digit - '0';
		}
		return value;
	}

	private static boolean hasNonEmptyOrderSlots(String plan) {
		int fromIndex = 0;
		while ((fromIndex = plan.indexOf("orderSlots=[", fromIndex)) >= 0) {
			int firstValue = fromIndex + "orderSlots=[".length();
			if (firstValue < plan.length() && plan.charAt(firstValue) != ']') {
				return true;
			}
			fromIndex = firstValue;
		}
		return false;
	}

	private static String findExecutionPath(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String path = node.getStringMetricActual(NATIVE_EXECUTION_PATH);
		if (path != null) {
			return path;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String childPath = findExecutionPath(child);
				if (childPath != null) {
					return childPath;
				}
			}
		}
		return null;
	}

	private static long findMaximumMetric(GenericPlanNode node, String metricName) {
		if (node == null) {
			return 0L;
		}
		Long current = node.getLongMetricActual(metricName);
		long maximum = current == null ? 0L : current;
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				maximum = Math.max(maximum, findMaximumMetric(child, metricName));
			}
		}
		return maximum;
	}

	record QueryDigest(long rowCount, long digest) {
		long folded() {
			return digest ^ Long.rotateLeft(rowCount, 17);
		}
	}

	record WorkloadEvidence(String executionPath, boolean nativeOrderSlots, long packedRows, long topKCandidates) {
	}

	enum Workload {
		FULL_SORT("SELECT ?label WHERE { ?item <" + EX + "label> ?label } ORDER BY ?label"),
		TOP_K("SELECT ?score WHERE { ?item <" + EX + "score> ?score } ORDER BY DESC(?score) LIMIT %d"),
		RADIX_ELIGIBLE("SELECT ?score WHERE { ?item <" + EX + "score> ?score } ORDER BY ?score"),
		EXPRESSION_KEYS(
				"SELECT ?label WHERE { ?item <" + EX + "label> ?label } ORDER BY DESC(STR(?label))"),
		ORDER_ELIMINATED("SELECT ?item ?score WHERE { ?item <" + EX + "score> ?score . ?item <" + EX
				+ "bonus> ?bonus } ORDER BY ?item");

		private final String queryTemplate;

		Workload(String queryTemplate) {
			this.queryTemplate = queryTemplate;
		}

		String query(int topK) {
			return this == TOP_K ? queryTemplate.formatted(topK) : queryTemplate;
		}
	}
